package com.google.gson.internal.reflect;
import com.google.gson.JsonIOException;
import com.google.gson.internal.GsonBuildConfig;
import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Constructor;
import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  // Create a helper interface with the same method signature as ReflectionHelper.RecordHelper
  private interface DummyRecordHelperInterface {
    String[] getRecordComponentNames(Class<?> raw);
  }

  // Create a helper class that implements the dummy interface
  private static class DummyRecordHelper implements DummyRecordHelperInterface {
    @Override
    public String[] getRecordComponentNames(Class<?> raw) {
      if (raw == null) {
        throw new NullPointerException();
      }
      if (raw == String.class) {
        return new String[] { "name", "value" };
      }
      return new String[0];
    }
  }

  @BeforeAll
  static void setUp() throws Exception {
    // Use reflection to get the private static final RECORD_HELPER field in ReflectionHelper
    Field field = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    field.setAccessible(true);

    // Remove final modifier if needed
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(field, field.getModifiers() & ~Modifier.FINAL);

    // Instead of using the RecordHelper class directly (which is a class, not interface),
    // create a proxy that implements the same interfaces as RECORD_HELPER's current value.
    Object originalRecordHelper = field.get(null);
    Class<?>[] interfaces;
    if (originalRecordHelper != null) {
      interfaces = originalRecordHelper.getClass().getInterfaces();
    } else {
      // fallback: find interfaces implemented by the RECORD_HELPER field type
      interfaces = new Class<?>[0];
    }

    // If no interfaces found, fallback to a single interface with a dynamic proxy that throws UnsupportedOperationException
    if (interfaces.length == 0) {
      // fallback: create a dummy interface with the method signature
      interfaces = new Class<?>[] {
          java.lang.reflect.Proxy.getProxyClass(ReflectionHelper.class.getClassLoader(), DummyRecordHelperInterface.class)
              .getInterfaces()[0]
      };
    }

    // Create a proxy instance that implements the same interfaces as originalRecordHelper or fallback to DummyRecordHelperInterface
    Class<?> recordHelperInterface = null;
    for (Class<?> innerClass : ReflectionHelper.class.getDeclaredClasses()) {
      if ("RecordHelper".equals(innerClass.getSimpleName()) && innerClass.isInterface()) {
        recordHelperInterface = innerClass;
        break;
      }
    }
    if (recordHelperInterface == null) {
      // fallback to dummy interface
      recordHelperInterface = DummyRecordHelperInterface.class;
    }

    Object proxyInstance = java.lang.reflect.Proxy.newProxyInstance(
        ReflectionHelper.class.getClassLoader(),
        new Class<?>[] { recordHelperInterface },
        (proxy, method, args) -> {
          if ("getRecordComponentNames".equals(method.getName())) {
            Class<?> raw = (Class<?>) args[0];
            if (raw == null) {
              throw new NullPointerException();
            }
            if (raw == String.class) {
              return new String[] { "name", "value" };
            }
            return new String[0];
          }
          throw new UnsupportedOperationException("Unsupported method: " + method.getName());
        });

    // Set the RECORD_HELPER field to the proxy instance
    field.set(null, proxyInstance);
  }

  @Test
  void getRecordComponentNames_nullClass_throwsNPE() {
    assertThrows(NullPointerException.class, () -> ReflectionHelper.getRecordComponentNames(null));
  }

  @Test
  void getRecordComponentNames_knownClass_returnsExpectedNames() {
    String[] names = ReflectionHelper.getRecordComponentNames(String.class);
    assertArrayEquals(new String[] { "name", "value" }, names);
  }

  @Test
  void getRecordComponentNames_unknownClass_returnsEmptyArray() {
    String[] names = ReflectionHelper.getRecordComponentNames(Integer.class);
    assertNotNull(names);
    assertEquals(0, names.length);
  }
}
